function initApp() {
  const input = document.getElementById("autocomplete");
  const suggestionsList = document.getElementById("suggestions");
  const detailsDiv = document.getElementById("details");
  const closeButton = document.getElementById("close-button");
  let debounceTimeout;
  const debounceDelay = 300;
  const predictionAPI = "https://n5j6f33icg.execute-api.eu-west-1.amazonaws.com/staging/maps/api/place/autocomplete/json";
  const detailsAPI = "https://n5j6f33icg.execute-api.eu-west-1.amazonaws.com/staging/maps/api/place/details/json";
  function fetchPredictions(query) {
    if (query.length === 0) {
      suggestionsList.innerHTML = "";
      closeButton.classList.add("d-none");
      return;
    }
    closeButton.classList.remove("d-none");
    fetch(`${predictionAPI}?input=${query}&components=country%3Afr&language=fr`).then(response => response.json()).then(data => {
      displaySuggestions(data.predictions);
    }).catch(err => console.error("Error fetching predictions:", err));
  }
  function displaySuggestions(predictions) {
    suggestionsList.innerHTML = "";
    predictions.forEach(prediction => {
      const li = document.createElement("li");
      li.textContent = prediction.description;
      li.addEventListener("click", () => {
        fetchDetails(prediction.place_id, prediction.description);
      });
      suggestionsList.appendChild(li);
    });
  }
  function parseAddress(details) {
    if (!details) return "";
    console.log(details);
    const addressComponents = {};
    details.address_components.forEach(item => {
      addressComponents[item.types[0]] = item.long_name;
    });
    const result = {
      name: details.name,
      placeId: details.place_id,
      gMapsUrl: details.url,
      fullAddress: details.formatted_address,
      streetNumber: addressComponents.street_number || "",
      route: addressComponents.route || "",
      locality: addressComponents.locality,
      administrativeAreaLevel1: addressComponents.administrative_area_level_1 || "",
      administrativeAreaLevel2: addressComponents.administrative_area_level_2 || "",
      country: addressComponents.country,
      postalCode: addressComponents.postal_code || ""
    };
    return result;
  }
  function fetchDetails(id, text) {
    suggestionsList.innerHTML = "";
    input.value = text;
    fetch(`${detailsAPI}?placeid=${id}&components=country%3Afr&language=fr`).then(response => response.json()).then(details => {
      appsmith.updateModel({
        data: parseAddress(details.result),
        hasValue: true
      });
      appsmith.triggerEvent("submitted");
    }).catch(err => console.error("Error fetching details:", err));
  }
  function debounce(func, delay) {
    return function () {
      const args = arguments;
      clearTimeout(debounceTimeout);
      debounceTimeout = setTimeout(() => func.apply(this, args), delay);
    };
  }
  closeButton.addEventListener("click", function () {
    input.value = "";
    suggestionsList.innerHTML = "";
    closeButton.classList.add("d-none");
  });
  input.addEventListener("input", debounce(function () {
    const query = this.value;
    fetchPredictions(query);
  }, debounceDelay));
}
appsmith.onReady(() => {
  /*
   * This handler function will get called when parent application is ready.
   * Initialize your component here
   * more info - https://docs.appsmith.com/reference/widgets/custom#onready
   */
  initApp();
});

